import (
	"container/heap"
	"sort"
)

type IntHeap []int64

func (h IntHeap) Len() int            { return len(h) }
func (h IntHeap) Less(i, j int) bool  { return h[i] > h[j] }
func (h IntHeap) Swap(i, j int)       { h[i], h[j] = h[j], h[i] }
func (h *IntHeap) Push(x interface{}) { *h = append(*h, x.(int64)) }
func (h *IntHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func solve(value []int64, limit []int64) int64 {
	n := int64(len(value))
	type Element struct {
		limit int64
		value int64
	}
	elements := make([]Element, n)
	for i := int64(0); i < n; i++ {
		elements[i] = Element{limit: limit[i], value: value[i]}
	}
	sort.Slice(elements, func(i, j int) bool {
		return elements[i].limit < elements[j].limit
	})

	h := &IntHeap{}
	heap.Init(h)

	sum := int64(0)
	idx := 0
	for k := int64(1); k <= n; k++ {
		for idx < len(elements) && elements[idx].limit <= k {
			heap.Push(h, elements[idx].value)
			idx++
		}
		if h.Len() > 0 {
			maxVal := heap.Pop(h).(int64)
			sum += maxVal
		}
	}
	return sum
}
