import (
    "sort"
)

type Fenw struct {
    tree []int64
    size int
}

func NewFenw(n int) *Fenw {
    return &Fenw{
        tree: make([]int64, n+1),
        size: n,
    }
}

func (f *Fenw) update(i int, delta int) {
    for i <= f.size {
        f.tree[i] += int64(delta)
        i += i & -i
    }
}

func (f *Fenw) query(i int) int64 {
    s := int64(0)
    for i > 0 {
        s += f.tree[i]
        i -= i & -i
    }
    return s
}

func (f *Fenw) queryRange(l, r int) int64 {
    if l > r {
        return 0
    }
    if l <= 1 {
        return f.query(r)
    }
    return f.query(r) - f.query(l-1)
}

type Element struct {
    limit int
    value int64
}

func solve(value []int64, limit []int64) int64 {
    n := len(value)
    if n == 0 {
        return 0
    }

    elements := make([]Element, n)
    for i := 0; i < n; i++ {
        elements[i] = Element{
            limit: int(limit[i]),
            value: value[i],
        }
    }

    sort.Slice(elements, func(i, j int) bool {
        if elements[i].limit != elements[j].limit {
            return elements[i].limit < elements[j].limit
        }
        return elements[i].value > elements[j].value
    })

    maxL := 100000
    tree := NewFenw(maxL)

    max_removal := 0
    activeCount := 0
    ans := int64(0)

    for i := 0; i < n; i++ {
        l := elements[i].limit
        v := elements[i].value

        if l <= max_removal {
            continue
        }

        if activeCount < l {
            ans += v
            tree.update(l, 1)

            candidate := activeCount + 1
            if candidate > max_removal {
                max_removal = candidate
            }

            next_low := max_removal + 1
            if next_low > maxL {
                activeCount = 0
            } else {
                activeCount = int(tree.queryRange(next_low, maxL))
            }
        }
    }

    return ans
}
```

