import (
	"container/heap"
)

type MinHeap []int64

func (h MinHeap) Len() int           { return len(h) }
func (h MinHeap) Less(i, j int) bool { return h[i] < h[j] }
func (h MinHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }
func (h *MinHeap) Push(x interface{}) {
	*h = append(*h, x.(int64))
}
func (h *MinHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func solve(value []int64, limit []int64) int64 {
	n := len(value)
	if n == 0 {
		return 0
	}

	max_limit := int64(0)
	for _, l := range limit {
		if l > max_limit {
			max_limit = l
		}
	}
	if max_limit > int64(n) {
		max_limit = int64(n)
	}

	lists := make([][]int64, max_limit+1)
	for i, l := range limit {
		if l <= max_limit {
			lists[l] = append(lists[l], value[i])
		}
	}

	h := &MinHeap{}
	heap.Init(h)

	for x := int64(1); x <= max_limit; x++ {
		for _, val := range lists[x] {
			heap.Push(h, val)
		}
		for h.Len() > int(x) {
			heap.Pop(h)
		}
	}

	ans := int64(0)
	for h.Len() > 0 {
		ans += heap.Pop(h).(int64)
	}

	return ans
}
